previewCss:
.darma-loader-darma-custom-525 {color: var(--loader-color, #059669);
   height: 30px;
   aspect-ratio: 1;
   display: grid;
   background: radial-gradient(farthest-side,currentColor 15%,#0000 18%), radial-gradient(50% 100% at 50% 160%,currentColor 95%,#0000) top/100% 50%, radial-gradient(50% 100% at 50% -60%,currentColor 95%,#0000) bottom/100% 50%;
   background-repeat: no-repeat;
}
.darma-loader-darma-custom-525:before  {
  content: "";
   background: inherit;
   opacity: 0.6;
   animation: darma-loader-darma-custom-525-l1 1s infinite;
}
@keyframes darma-loader-darma-custom-525-l1  {
  to {transform:scale(3);
  opacity:0}
}

